import{_ as s,c as o,o as e,aa as a}from"./chunks/framework.DZPhBpRd.js";const u=JSON.parse('{"title":"giscus 评论数抓取逻辑","description":"梳理 giscus 评论数的获取、路径匹配与映射逻辑，供实现或排查参考","frontmatter":{"title":"giscus 评论数抓取逻辑","description":"梳理 giscus 评论数的获取、路径匹配与映射逻辑，供实现或排查参考","date":"2026-03-02T00:00:00.000Z","tags":["giscus"]},"headers":[],"relativePath":"posts/giscus评论数抓取逻辑.md","filePath":"posts/giscus评论数抓取逻辑.md","lastUpdated":1772589498000}'),n={name:"posts/giscus评论数抓取逻辑.md"};function d(i,t,c,l,r,p){return e(),o("div",null,[...t[0]||(t[0]=[a(`<blockquote><p>本文只讲评论数量获取的核心逻辑，不涉及具体前端实现。文末附带实现时需注意的坑与提醒。</p></blockquote><h2 id="_1-核心定位" tabindex="-1">1. 核心定位 <a class="header-anchor" href="#_1-核心定位" aria-label="Permalink to &quot;1. 核心定位&quot;">​</a></h2><p>本方案为<strong>纯前端静态实现</strong>：无后端、无本地 JSON 文件维护，评论数由前端实时请求 GitHub GraphQL API 获取。配置一个仅具 <strong>Discussions 读权限</strong> 的 token 供前端使用，既可提高 API 限速，又保证权限最小化。</p><h2 id="_2-背景与约定" tabindex="-1">2. 背景与约定 <a class="header-anchor" href="#_2-背景与约定" aria-label="Permalink to &quot;2. 背景与约定&quot;">​</a></h2><ul><li><strong>giscus 约定</strong>：使用 <code>mapping: &quot;pathname&quot;</code> 时，GitHub Discussion 的 <code>title</code> 即为页面 pathname</li><li><strong>站点约定</strong>：文章有 <code>regularPath</code>（如 <code>/posts/xxx.html</code>）</li><li><strong>匹配前提</strong>：Discussion title 与 regularPath 经同一套标准化后能一一对应</li></ul><h2 id="_3-整体逻辑" tabindex="-1">3. 整体逻辑 <a class="header-anchor" href="#_3-整体逻辑" aria-label="Permalink to &quot;3. 整体逻辑&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[拉取] 前端请求 GitHub GraphQL API，获取 Discussions</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[构建映射] 对每个 node.title 做 decodeURIComponent + normalizePath 得到 key，累加 totalCount 到内存中的 path → count 映射</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[按 path 查找] 对 regularPath 做 normalizePath 得到 key，在映射中取数</span></span></code></pre></div><p>其中「构建映射」和「按 path 查找」均在前端内存中完成，无需数据库或本地文件。</p><h2 id="_4-路径标准化" tabindex="-1">4. 路径标准化 <a class="header-anchor" href="#_4-路径标准化" aria-label="Permalink to &quot;4. 路径标准化&quot;">​</a></h2><p>两处必须用同一套规则：<strong>构建映射时</strong>（处理 Discussion title）和<strong>按 path 查找时</strong>（处理 regularPath）。</p><p>规则（顺序执行）：</p><ol><li>确保以 <code>/</code> 开头</li><li>去掉 <code>.md</code>、<code>.html</code> 后缀</li><li>将 <code>/index</code> 替换为 <code>/</code></li><li>去掉末尾的 <code>/</code>（根路径 <code>/</code> 除外）</li></ol><p>示例：</p><table tabindex="0"><thead><tr><th>输入</th><th>输出</th></tr></thead><tbody><tr><td><code>posts/千帆财富自由计划.md</code></td><td><code>/posts/千帆财富自由计划</code></td></tr><tr><td><code>posts/%E5%8D%83...</code>（解码后）</td><td><code>/posts/千帆财富自由计划</code></td></tr><tr><td><code>/posts/xxx.html</code></td><td><code>/posts/xxx</code></td></tr><tr><td><code>about</code></td><td><code>/about</code></td></tr></tbody></table><h2 id="_5-数据拉取" tabindex="-1">5. 数据拉取 <a class="header-anchor" href="#_5-数据拉取" aria-label="Permalink to &quot;5. 数据拉取&quot;">​</a></h2><ul><li><strong>接口</strong>：<code>https://api.github.com/graphql</code></li><li><strong>查询</strong>：<code>repository(owner, name).discussions(first: 100, categoryId, after: cursor)</code></li><li><strong>返回</strong>：<code>nodes[].title</code>、<code>nodes[].comments.totalCount</code></li><li><strong>分页</strong>：若 <code>hasNextPage</code> 为 true，用 <code>endCursor</code> 继续请求</li></ul><h2 id="_6-构建映射与按-path-查找" tabindex="-1">6. 构建映射与按 path 查找 <a class="header-anchor" href="#_6-构建映射与按-path-查找" aria-label="Permalink to &quot;6. 构建映射与按 path 查找&quot;">​</a></h2><p><strong>构建映射</strong>：对每个 Discussion node</p><ol><li><code>decodeURIComponent(node.title)</code>（GitHub 存的是 URL 编码）</li><li><code>normalizePath(decodedTitle)</code> 得到 key</li><li>将 <code>node.comments.totalCount</code> 累加到 <code>counts[key]</code>（同一 key 有多条讨论时合并）</li></ol><p>映射仅存在于前端内存中，不落盘、不写文件。</p><p><strong>按 path 查找</strong>：对传入的 regularPath</p><ol><li><code>normalizePath(regularPath)</code> 得到 key</li><li>返回 <code>counts[key] ?? 0</code></li></ol><h2 id="_7-数据流示意" tabindex="-1">7. 数据流示意 <a class="header-anchor" href="#_7-数据流示意" aria-label="Permalink to &quot;7. 数据流示意&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub Discussion.title: &quot;posts/%E5%8D%83...&quot;</span></span>
<span class="line"><span>        ↓ decodeURIComponent</span></span>
<span class="line"><span>        &quot;posts/千帆财富自由计划&quot;</span></span>
<span class="line"><span>        ↓ normalizePath</span></span>
<span class="line"><span>key: &quot;/posts/千帆财富自由计划&quot;  →  counts[&quot;/posts/千帆财富自由计划&quot;] = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>regularPath: &quot;/posts/千帆财富自由计划.html&quot;</span></span>
<span class="line"><span>        ↓ normalizePath</span></span>
<span class="line"><span>key: &quot;/posts/千帆财富自由计划&quot;  →  按 path 查找 → 1</span></span></code></pre></div><h2 id="_8-实现时需注意的坑" tabindex="-1">8. 实现时需注意的坑 <a class="header-anchor" href="#_8-实现时需注意的坑" aria-label="Permalink to &quot;8. 实现时需注意的坑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要点</th><th>说明</th></tr></thead><tbody><tr><td><strong>URL 解码</strong></td><td>GitHub Discussion title 多为 <code>posts/%E5%8D%83...</code> 形式，构建映射前必须先 <code>decodeURIComponent</code>，否则 key 对不上</td></tr><tr><td><strong>配置统一</strong></td><td>repo、categoryId 需与 giscus 评论组件共用同一份配置，否则可能拉不到或拉错讨论</td></tr><tr><td><strong>请求头</strong></td><td>GraphQL 请求需带 <code>Accept: application/vnd.github+json</code>、<code>User-Agent</code>，否则 GitHub 可能直接拒绝</td></tr><tr><td><strong>Token</strong></td><td>建议配置 token 提高限速；仅需 Discussions 读权限，权限最小化</td></tr><tr><td><strong>响应式</strong></td><td>若在 SPA 中展示，需确保数据异步加载完成后能触发 UI 更新（如显式依赖内存中的映射）</td></tr><tr><td><strong>路径格式</strong></td><td>giscus 存的是 <code>posts/xxx</code>（无前导 <code>/</code>），标准化时要统一补 <code>/</code>，保证构建映射与按 path 查找的 key 一致</td></tr></tbody></table>`,26)])])}const g=s(n,[["render",d]]);export{u as __pageData,g as default};
